class DynamicArray {
  constructor() { this.cap = 1; this.size = 0; this.arr = new Array(1); }
  get(i) { return this.arr[i]; }
  set(i, val) { this.arr[i] = val; }
  pushback(val) {
    if (this.size === this.cap) this.resize();
    this.arr[this.size++] = val;
  }
  popback() { return this.arr[--this.size]; }
  resize() {
    this.cap *= 2;
    const newArr = new Array(this.cap);
    for (let i = 0; i < this.size; i++) newArr[i] = this.arr[i];
    this.arr = newArr;
  }
  getSize() { return this.size; }
  getCapacity() { return this.cap; }
}
